"""Automated brute-force search for shorter p= lambda solutions.
Self-contained checker (inlined) to avoid dependency on files other agents may rename.
Run: python3 workdir/agentC_search_1.py
"""
import sys, json, random, os
os.chdir('/Users/jackson/Desktop/code-golf/deepseek-v4-pro-default/task004')
sys.path.insert(0, '.')
from gen import validate
import gen

_D = validate()
_ARC = json.load(open('data.json'))['arc-gen']
# Precompute random samples once
random.seed(3)
_RND = [gen.generate() for _ in range(2000)]

def check(code):
    G = {}
    try:
        exec(code, G)
        p = G['p']
        for split in ('train', 'test'):
            for ex in _D[split]:
                if p(ex['input']) != ex['output']:
                    return False, 'validate'
        for e in _ARC:
            if p(e['input']) != e['output']:
                return False, 'arc-gen'
        for ex in _RND:
            if p(ex['input']) != ex['output']:
                return False, 'random'
    except Exception as ex:
        return False, 'err:'+str(ex)[:30]
    return True, len(code)

def test(code):
    ok, info = check(code)
    return ok, info

if __name__ == '__main__':
    cands = [
     "p=lambda g:[[[y,x][u<any(b)]for x,y,u in zip([0]+a,a,[0]+b)]for a,b in zip(g,g[1:]+g)]",
     "p=lambda g:[[[y,x][u<max(b)]for x,y,u in zip([0]+a,a,[0]+b)]for a,b in zip(g,g[1:]+g)]",
     "p=lambda g:[[0]+[[y,x][u<any(b)]for x,y,u in zip(a,a[1:],b)]for a,b in zip(g,g[1:]+g)]",
     "p=lambda g:[[0]+[[y,x][u<max(b)]for x,y,u in zip(a,a[1:],b)]for a,b in zip(g,g[1:]+g)]",
     "p=lambda g:[[(y,x)[u<any(b)]for x,y,u in zip([0]+a,a,[0]+b)]for a,b in zip(g,g[1:]+g)]",
    ]
    results = []
    for c in cands:
        ok, info = test(c)
        results.append((len(c), ok, c, info))
        print(len(c), "OK" if ok else "FAIL "+info, c[:55])
    results = [r for r in results if r[1]]
    results.sort()
    print("\nBEST OK:")
    for r in results[:5]:
        print(r[0], r[2])

