"""Deletion + substitution mutation search on the baseline."""
import sys, json, random, os, itertools
os.chdir('/Users/jackson/Desktop/code-golf/deepseek-v4-pro-default/task004')
sys.path.insert(0,'.')
from gen import validate
import gen
_D=validate(); _ARC=json.load(open('data.json'))['arc-gen']
random.seed(3); _RND=[gen.generate() for _ in range(2000)]
def check(code):
    G={}
    try:
        exec(code,G); p=G['p']
        for s in('train','test'):
            for ex in _D[s]:
                if p(ex['input'])!=ex['output']: return False
        for e in _ARC:
            if p(e['input'])!=e['output']: return False
        for ex in _RND:
            if p(ex['input'])!=ex['output']: return False
    except Exception:
        return False
    return True

base="p=lambda g:[[[y,x][u<any(b)]for x,y,u in zip([0]+a,a,[0]+b)]for a,b in zip(g,g[1:]+g)]"
found=set()
# single & double & triple char deletions
tested=0
for k in (1,2,3):
    for i in range(len(base)-k+1):
        cand=base[:i]+base[i+k:]
        tested+=1
        if len(cand)<len(base) and check(cand):
            found.add(cand)
print("deletion tested",tested,"found",len(found))
for f in sorted(found,key=len):
    print(len(f),f)

# token substitutions (equivalences)
subs=[("any(b)","max(b)"),("[y,x]","(y,x)"),("g[1:]+g","g[1:]+g"),
      ("[0]+a","a[-1:]+a"),]
import re
variants={base}
for old,new in subs:
    for v in list(variants):
        if old in v:
            variants.add(v.replace(old,new))
found2=set()
for v in variants:
    if len(v)<len(base) and check(v):
        found2.add(v)
print("\nsub found",len(found2))
for f in sorted(found2,key=len):
    print(len(f),f)

