"""Scan every candidate .py in workdir; report shortest that PASSES full check."""
import sys, json, random, os, glob
os.chdir('/Users/jackson/Desktop/code-golf/deepseek-v4-pro-default/task004')
sys.path.insert(0,'.')
from gen import validate
import gen
_D=validate(); _ARC=json.load(open('data.json'))['arc-gen']
random.seed(3); _RND=[gen.generate() for _ in range(2000)]
def check(code):
    G={}
    try:
        exec(code,G); p=G['p']
        for s in('train','test'):
            for ex in _D[s]:
                if p(ex['input'])!=ex['output']: return False
        for e in _ARC:
            if p(e['input'])!=e['output']: return False
        for ex in _RND:
            if p(ex['input'])!=ex['output']: return False
    except Exception:
        return False
    return True

rows=[]
for f in glob.glob('workdir/*.py'):
    try:
        code=open(f).read().strip()
    except Exception:
        continue
    if 'p=lambda' not in code and 'def p' not in code:
        continue
    # only single-expression solution files (skip harness/checker files)
    if 'check(' in code or 'validate()' in code or 'import ' in code.split('\n')[0]:
        continue
    ok=check(code)
    rows.append((len(code),ok,os.path.basename(f),code[:70]))
rows.sort()
print("size OK file")
for L,ok,f,code in rows:
    print(L, "PASS" if ok else "FAIL", f)
passing=[r for r in rows if r[1]]
print("\nSHORTEST PASSING:")
if passing:
    L,ok,f,code=passing[0]
    print(L,f)
    print(open('workdir/'+f).read().strip())

